previewCss:
.darma-loader-darma-custom-578 {color: var(--loader-color, #059669);
  --loader-secondary-color: var(--loader-secondary-color, #2dd4bf);
  --loader-bg: var(--loader-bg, #ffffff);
   width: 30px;
   aspect-ratio: 1;
   background: var(--loader-color, #059669);
   display: grid;
   transform-origin: top right;
   animation: darma-loader-darma-custom-578-l5-0 4s infinite linear;
}
.darma-loader-darma-custom-578::before, .darma-loader-darma-custom-578::after  {
  content: "";
   grid-area: 1/1;
   background: var(--loader-color, #059669);
   transform-origin: inherit;
   animation: inherit;
   animation-name: darma-loader-darma-custom-578-l5-1;
   animation-duration: 1s;
}
.darma-loader-darma-custom-578::after  {
  background:var(--loader-color, #059669);
   --s:60deg;
}
@keyframes darma-loader-darma-custom-578-l5-0  {
  0%,5% {transform: rotate(0)}
25%,30% {transform: rotate(90deg)}
50%,55% {transform: rotate(180deg)}
75%,80% {transform: rotate(270deg)}
100% {transform: rotate(360deg)}
}
@keyframes darma-loader-darma-custom-578-l5-1  {
  50% {transform: rotate(var(--s,30deg))}
100% {transform: rotate(0)}
}

